1833	static void model_prefetch_cpu_mapping(const ds4_model *m) {
1834	    if (!m || !m->map || m->size == 0) return;
1835	
1836	    /*
1837	     * CPU generation touches expert weights according to router decisions, so a
1838	     * long decode can fault in model pages that the prompt never touched. On
1839	     * current Darwin kernels we have seen those late file-backed faults trigger
1840	     * an OS-level VM panic in map-count accounting. This hint does not copy or
1841	     * pin the GGUF; it just asks the kernel to start bringing the read-only
1842	     * mapping into the page cache before token generation reaches it.
1843	     */
1844	#if defined(POSIX_MADV_WILLNEED)
1845	    const int rc = posix_madvise((void *)m->map, (size_t)m->size, POSIX_MADV_WILLNEED);
1846	    if (rc != 0) {
1847	        ds4_log(stderr,
1848	                DS4_LOG_WARNING,
1849	                "ds4: warning: POSIX_MADV_WILLNEED failed for CPU model mapping: %s\n",
1850	                strerror(rc));
1851	    }
1852	#else
1853	    (void)m;
1854	#endif
1855	}
