1857	/* Read the GGUF metadata table.  Values stay in the mmap; we store offsets so
1858	 * later validation can decode only the keys it needs. */
1859	static void parse_metadata(ds4_model *m, ds4_cursor *c) {
1860	    m->kv = calloc((size_t)m->n_kv, sizeof(m->kv[0]));
1861	    if (!m->kv) ds4_die("out of memory while allocating metadata table");
1862	
1863	    m->alignment = 32;
1864	
1865	    for (uint64_t i = 0; i < m->n_kv; i++) {
1866	        ds4_kv *kv = &m->kv[i];
1867	
1868	        if (!cursor_string(c, &kv->key)) ds4_die(c->error);
1869	        if (!cursor_u32(c, &kv->type)) ds4_die(c->error);
1870	
1871	        kv->value_pos = c->pos;
1872	
1873	        if (ds4_streq(kv->key, "general.alignment") &&
1874	            kv->type == GGUF_VALUE_UINT32)
1875	        {
1876	            ds4_cursor tmp = cursor_at(m, kv->value_pos);
1877	            uint32_t alignment;
1878	            if (cursor_u32(&tmp, &alignment) && alignment != 0) {
1879	                m->alignment = alignment;
1880	            }
1881	        }
1882	
1883	        if (!skip_value(c, kv->type, 0)) ds4_die(c->error);
1884	    }
1885	}
