1887	/* Read the tensor directory and convert relative GGUF offsets to absolute
1888	 * mmap offsets.  Tensor bytes are still never copied here. */
1889	static void parse_tensors(ds4_model *m, ds4_cursor *c) {
1890	    m->tensors = calloc((size_t)m->n_tensors, sizeof(m->tensors[0]));
1891	    if (!m->tensors) ds4_die("out of memory while allocating tensor table");
1892	
1893	    for (uint64_t i = 0; i < m->n_tensors; i++) {
1894	        ds4_tensor *t = &m->tensors[i];
1895	
1896	        if (!cursor_string(c, &t->name)) ds4_die(c->error);
1897	        if (!cursor_u32(c, &t->ndim)) ds4_die(c->error);
1898	        if (t->ndim == 0 || t->ndim > DS4_MAX_DIMS) {
1899	            ds4_die("tensor has an unsupported number of dimensions");
1900	        }
1901	
1902	        t->elements = 1;
1903	        for (uint32_t d = 0; d < t->ndim; d++) {
1904	            if (!cursor_u64(c, &t->dim[d])) ds4_die(c->error);
1905	            if (t->dim[d] != 0 && t->elements > UINT64_MAX / t->dim[d]) {
1906	                ds4_die("tensor element count overflow");
1907	            }
1908	            t->elements *= t->dim[d];
1909	        }
1910	
1911	        if (!cursor_u32(c, &t->type)) ds4_die(c->error);
1912	        if (!cursor_u64(c, &t->rel_offset)) ds4_die(c->error);
1913	
1914	        if (!tensor_nbytes(t->type, t->elements, &t->bytes)) {
1915	            ds4_log(stderr,
1916	                DS4_LOG_WARNING,
1917	                "ds4: warning: tensor %.*s has unsupported GGUF type %u\n",
1918	                (int)t->name.len, t->name.ptr, t->type);
1919	        }
1920	    }
1921	
1922	    m->tensor_data_pos = align_up(c->pos, m->alignment);
1923	
1924	    for (uint64_t i = 0; i < m->n_tensors; i++) {
1925	        ds4_tensor *t = &m->tensors[i];
1926	        if (t->rel_offset > UINT64_MAX - m->tensor_data_pos) {
1927	            ds4_die("tensor offset overflow");
1928	        }
1929	        t->abs_offset = m->tensor_data_pos + t->rel_offset;
1930	        if (t->bytes != 0 &&
1931	            (t->abs_offset > m->size || t->bytes > m->size - t->abs_offset))
1932	        {
1933	            ds4_die("tensor points outside GGUF file");
1934	        }
1935	        if (t->bytes > m->max_tensor_bytes) {
