1941	/* Open and map the GGUF once.  Metal needs a shared mapping for no-copy
1942	 * MTLBuffers; CPU uses a private read-only mapping to avoid Darwin VM stress.
1943	 * Tokenizer-only callers pass prefetch_cpu=false so inspecting tokens never
1944	 * walks the huge tensor payload. */
1945	static void model_open(ds4_model *m, const char *path, bool metal_mapping,
1946	                       bool prefetch_cpu) {
1947	    memset(m, 0, sizeof(*m));
1948	    m->fd = -1;
1949	
1950	    int fd = open(path, O_RDONLY);
1951	    if (fd == -1) ds4_die_errno("cannot open model", path);
1952	
1953	    struct stat st;
1954	    if (fstat(fd, &st) == -1) ds4_die_errno("cannot stat model", path);
1955	    if (st.st_size < 32) ds4_die("model file is too small to be GGUF");
1956	
1957	    /*
1958	     * Metal wraps slices of this mapping as no-copy MTLBuffers, so the Metal
1959	     * path keeps the file-backed shared mapping. The CPU path only reads the
1960	     * weights through normal pointers and should not inherit Metal's VM policy:
1961	     * use a private read-only mapping there.
1962	     *
1963	     * This is deliberately defensive against an OS-level Darwin VM bug observed
1964	     * while the CPU backend streams the very large GGUF through a shared mmap:
1965	     * the kernel can panic in VM map-count accounting instead of returning a
1966	     * normal user-space failure. Keeping CPU inference off the shared mapping
1967	     * avoids that VM accounting path while preserving normal file-backed reads.
1968	     */
1969	    const int mmap_flags = metal_mapping ? MAP_SHARED : MAP_PRIVATE;
1970	    void *map = mmap(NULL, (size_t)st.st_size, PROT_READ, mmap_flags, fd, 0);
1971	    if (map == MAP_FAILED) ds4_die_errno("cannot mmap model", path);
1972	
1973	    m->fd = fd;
1974	    m->map = map;
1975	    m->size = (uint64_t)st.st_size;
1976	
1977	    ds4_cursor c = cursor_at(m, 0);
1978	    uint32_t magic;
1979	    if (!cursor_u32(&c, &magic)) ds4_die(c.error);
1980	    if (magic != DS4_GGUF_MAGIC) ds4_die("model is not a GGUF file");
1981	    if (!cursor_u32(&c, &m->version)) ds4_die(c.error);
1982	    if (!cursor_u64(&c, &m->n_tensors)) ds4_die(c.error);
1983	    if (!cursor_u64(&c, &m->n_kv)) ds4_die(c.error);
1984	
1985	    if (m->version != 3) ds4_die("only GGUF v3 is supported");
1986	
1987	    parse_metadata(m, &c);
1988	    parse_tensors(m, &c);
1989	
1990	    if (!metal_mapping && prefetch_cpu) model_prefetch_cpu_mapping(m);
1991	}
